function route(name){let raw=name||location.hash.replace('#','')||state.route||'match',r=normalizeRoute(raw);if(r==='jouer'&&!isMatchStarted()){requestStartPlay('#jouer');r='alignement'}let previous=state.route;state.route=r;save();if(raw!==r&&location.hash)history.replaceState(null,'','#'+r);$$('.view').forEach(v=>v.classList.toggle('active',v.id==='view-'+r));$$('[data-nav],[data-step]').forEach(a=>a.classList.toggle('active',(a.dataset.nav||a.dataset.step)===r));$('#nav').classList.remove('open');let more=$('.navMore');if(more)more.classList.remove('open');let moreBtn=$('#moreBtn');if(moreBtn)moreBtn.setAttribute('aria-expanded','false');if(r!==previous)window.scrollTo({top:0,left:0,behavior:'auto'});if(r==='spectateur')renderMatch();if(r==='jouer')renderPlay();}
