function generateAll(){if(isMatchStarted()){modal('Match débuté','Optimiser est désactivé quand le match est débuté. Ajuste les manches restantes manuellement.');return}state.order=state.players.map(p=>p.id);state.battingOrders={};let a=active();if(a.length<MIN||a.length>MAX){modal('Alignement impossible','Il faut entre 6 et 12 joueurs actifs.');return}let sched=[];for(let i=0;i<state.innings;i++)sched.push(generateInning(i,sched));state.schedule=sched;optimizeDirty=false;save();renderAll()}
