function makeFirstBaseSuggestion(id,ins){let inning=ins[1];let target=active().map(p=>p.id).find(other=>other!==id&&state.schedule[inning].pos[other]&&state.schedule[inning].pos[other]!=='1B'&&!hasPlayed(other,'1B',inning));return{level:'bad',title:player(id).name+' joue 1B plus d’une fois',text:target?'Échanger '+player(id).name+' (1B) avec '+player(target).name+' ('+state.schedule[inning].pos[target]+') à la manche '+(inning+1)+'.':'Aucune correction simple trouvée automatiquement.',action:target?{type:'swap',inning,id,target}:null}}
